-- Questions v2 (Decision 21: the office-worker rewrite).
-- New set published, old set archived — §4.5 immutability preserved.
-- Signal structure mirrors v1 one-to-one (same competencies and weights per
-- option intent), so scoring balance is unchanged.
-- Competencies: 1 curiosity · 2 problem-solving · 3 decision-making ·
-- 4 learning-agility · 5 efficiency · 6 workflow-design · 7 judgment · 8 vision

insert into public.questions (id, title, scenario, status) values
  ('d2000000-0000-4000-8000-000000000001', 'The 4:50pm email',
   'A teammate asks you to quickly check an important customer email that AI wrote for them. It goes out at 5:00.', 'published'),
  ('d2000000-0000-4000-8000-000000000002', 'The new AI tool',
   'Your company just gave everyone a new AI assistant. Your week is already full.', 'published'),
  ('d2000000-0000-4000-8000-000000000003', 'The Monday report',
   'Every Monday you spend two hours writing the same status report for your manager.', 'published'),
  ('d2000000-0000-4000-8000-000000000004', 'The wrong summary',
   'You ask AI to summarize a long meeting recording. The summary gets the main decision wrong.', 'published'),
  ('d2000000-0000-4000-8000-000000000005', 'The salary spreadsheet',
   'HR asks you to tidy up a spreadsheet — it has everyone''s salaries in it. AI would finish it in minutes.', 'published'),
  ('d2000000-0000-4000-8000-000000000006', 'The time-saver',
   'You''ve found an AI trick that saves you three hours a week. Nobody else knows yet.', 'published'),
  ('d2000000-0000-4000-8000-000000000007', 'The second opinion',
   'AI suggests a completely different approach to a proposal than what a senior colleague told you to do.', 'published'),
  ('d2000000-0000-4000-8000-000000000008', 'The team meeting',
   'In the planning meeting, your boss asks: "Where could AI actually help our team next quarter?"', 'published')
on conflict (id) do nothing;

insert into public.answer_options (id, question_id, content, author_position) values
  -- Q1: the 4:50pm email
  ('e2000000-0000-4000-8000-000000000011', 'd2000000-0000-4000-8000-000000000001', 'Read the two or three lines that could cause real trouble, and check those.', 1),
  ('e2000000-0000-4000-8000-000000000012', 'd2000000-0000-4000-8000-000000000001', 'Paste it back into AI and ask "what''s wrong with this email?"', 2),
  ('e2000000-0000-4000-8000-000000000013', 'd2000000-0000-4000-8000-000000000001', 'Tell them to send it — they know the customer better than you do.', 3),
  ('e2000000-0000-4000-8000-000000000014', 'd2000000-0000-4000-8000-000000000001', 'Ask the customer contact for 30 more minutes and check every line.', 4),
  -- Q2: the new AI tool
  ('e2000000-0000-4000-8000-000000000021', 'd2000000-0000-4000-8000-000000000002', 'Give it your trickiest task from last week and see what happens.', 1),
  ('e2000000-0000-4000-8000-000000000022', 'd2000000-0000-4000-8000-000000000002', 'Read the company''s do''s and don''ts first so you start on the right foot.', 2),
  ('e2000000-0000-4000-8000-000000000023', 'd2000000-0000-4000-8000-000000000002', 'Ask a colleague who''s tried it which two things are actually worth using.', 3),
  ('e2000000-0000-4000-8000-000000000024', 'd2000000-0000-4000-8000-000000000002', 'Swap one small everyday task into it this week, another next week.', 4),
  -- Q3: the Monday report
  ('e2000000-0000-4000-8000-000000000031', 'd2000000-0000-4000-8000-000000000003', 'Save your best prompt and notes so AI writes the first draft the same way every week.', 1),
  ('e2000000-0000-4000-8000-000000000032', 'd2000000-0000-4000-8000-000000000003', 'Paste this week''s updates into AI each Monday and tidy up whatever comes out.', 2),
  ('e2000000-0000-4000-8000-000000000033', 'd2000000-0000-4000-8000-000000000003', 'Keep writing it yourself — your manager reads it closely and the details matter.', 3),
  ('e2000000-0000-4000-8000-000000000034', 'd2000000-0000-4000-8000-000000000003', 'Suggest the whole team does their reports this way — set it up once for everyone.', 4),
  -- Q4: the wrong summary
  ('e2000000-0000-4000-8000-000000000041', 'd2000000-0000-4000-8000-000000000004', 'Give it the recording again in smaller pieces and check each part.', 1),
  ('e2000000-0000-4000-8000-000000000042', 'd2000000-0000-4000-8000-000000000004', 'Ask it why it thought that was the decision — you want to know where it went wrong.', 2),
  ('e2000000-0000-4000-8000-000000000043', 'd2000000-0000-4000-8000-000000000004', 'Write the summary yourself now and worry about the tool later.', 3),
  ('e2000000-0000-4000-8000-000000000044', 'd2000000-0000-4000-8000-000000000004', 'Check the summary against your own notes before trusting any of it.', 4),
  -- Q5: the salary spreadsheet
  ('e2000000-0000-4000-8000-000000000051', 'd2000000-0000-4000-8000-000000000005', 'Take the names and salaries out first, then let AI sort the rest.', 1),
  ('e2000000-0000-4000-8000-000000000052', 'd2000000-0000-4000-8000-000000000005', 'Ask your manager if it''s okay to use AI for this one.', 2),
  ('e2000000-0000-4000-8000-000000000053', 'd2000000-0000-4000-8000-000000000005', 'Just use AI — it stays inside the company anyway.', 3),
  ('e2000000-0000-4000-8000-000000000054', 'd2000000-0000-4000-8000-000000000005', 'Set it up so the private details come out automatically every time — then anyone on the team can do this safely.', 4),
  -- Q6: the time-saver
  ('e2000000-0000-4000-8000-000000000061', 'd2000000-0000-4000-8000-000000000006', 'Write it up and share it with the whole team.', 1),
  ('e2000000-0000-4000-8000-000000000062', 'd2000000-0000-4000-8000-000000000006', 'Keep polishing it on your own until you''re sure it always works.', 2),
  ('e2000000-0000-4000-8000-000000000063', 'd2000000-0000-4000-8000-000000000006', 'Show your manager and suggest trying it with two other people first.', 3),
  ('e2000000-0000-4000-8000-000000000064', 'd2000000-0000-4000-8000-000000000006', 'Enjoy the extra three hours for your most important work.', 4),
  -- Q7: the second opinion
  ('e2000000-0000-4000-8000-000000000071', 'd2000000-0000-4000-8000-000000000007', 'Try both on a small piece and see which works better.', 1),
  ('e2000000-0000-4000-8000-000000000072', 'd2000000-0000-4000-8000-000000000007', 'Go with your colleague — they know things the AI doesn''t.', 2),
  ('e2000000-0000-4000-8000-000000000073', 'd2000000-0000-4000-8000-000000000007', 'Show your colleague the AI''s idea and ask them to poke holes in it.', 3),
  ('e2000000-0000-4000-8000-000000000074', 'd2000000-0000-4000-8000-000000000007', 'Ask the AI to argue your colleague''s side as hard as it can, then compare.', 4),
  -- Q8: the team meeting
  ('e2000000-0000-4000-8000-000000000081', 'd2000000-0000-4000-8000-000000000008', 'Walk through how the team works and point at the steps AI could take over completely.', 1),
  ('e2000000-0000-4000-8000-000000000082', 'd2000000-0000-4000-8000-000000000008', 'Suggest giving everyone a bit of time each week to get better at using AI.', 2),
  ('e2000000-0000-4000-8000-000000000083', 'd2000000-0000-4000-8000-000000000008', 'Point AI at the one thing slowing everyone down right now, and measure it.', 3),
  ('e2000000-0000-4000-8000-000000000084', 'd2000000-0000-4000-8000-000000000008', 'Say it''s safer to decide task by task as real needs come up.', 4)
on conflict (id) do nothing;

